#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int t,n,m,p;

int quick_mi(int a,int b,int p){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%p;
        base=base*base%p,b>>=1;
    }
    return ans;
}

int C(int n,int m,int p){
    if(n<m)
        return 0;
    long long ans=1;
    for(int i=n;i>n-m;i--)
        ans=ans*i%p;
    for(int i=2;i<=m;i++)
        ans=ans*quick_mi(i,p-2,p)%p;
    return ans;
}

int Lucas(int n,int m,int p){
    long long ans=1;
    while(n && m && ans){
        ans=ans*C(n%p,m%p,p)%p;
        n/=p,m/=p;
    }
    return ans;
}

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d%d",&n,&m,&p);
        printf("%d\n",Lucas(n+m,n,p));
    }
    return 0;
}
